const CSS = `
@import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&family=Lora:ital,wght@0,600;1,500&family=Barlow:wght@400;500;600;700&display=swap');

/* ── RESET & VARS ─────────────────────────────────────────────────────── */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

:root {
  --red:        #c8102e;
  --red-light:  #e8162e;
  --red-dark:   #8b0000;
  --gold:       #f4a623;
  --black:      #0d0d0d;
  --charcoal:   #161616;
  --white:      #ffffff;
  --muted:      rgba(255,255,255,0.55);
  --border:     rgba(255,255,255,0.07);
  --font-display: 'Bebas Neue', sans-serif;
  --font-serif:   'Lora', serif;
  --font-body:    'Barlow', sans-serif;
  --radius:     4px;
  --radius-lg:  12px;
  --shadow:     0 8px 40px rgba(0,0,0,0.45);
  --shadow-dark:0 20px 60px rgba(0,0,0,0.65);
  --nav-height: 72px;
  --ease:       cubic-bezier(0.4,0,0.2,1);
}

.home-page {
  font-family: var(--font-body);
  background: var(--black);
  color: var(--white);
  overflow-x: hidden;
}

/* ── PLACEHOLDERS ─────────────────────────────────────────────────────── */
.placeholder-img {
  background: linear-gradient(135deg, #1e1e1e 0%, #2a2a2a 100%);
  border-radius: inherit;
  display: flex; align-items: center; justify-content: center;
  overflow: hidden; position: relative;
}
.placeholder-img::before {
  content: ''; position: absolute; inset: 0;
  background: linear-gradient(135deg, rgba(200,16,46,0.1), rgba(244,166,35,0.05));
}
.placeholder-img.accent::before {
  background: linear-gradient(135deg, rgba(200,16,46,0.2), rgba(244,166,35,0.15));
}
.placeholder-inner {
  display: flex; flex-direction: column; align-items: center; gap: 8px;
  position: relative; z-index: 1;
}
.placeholder-icon  { font-size: 2.4rem; filter: grayscale(0.3); }
.placeholder-label { font-family: var(--font-body); font-size: 0.72rem; color: rgba(255,255,255,0.28); letter-spacing: 0.12em; text-transform: uppercase; }

/* ── SHARED BUTTONS ───────────────────────────────────────────────────── */
button { cursor: pointer; font-family: var(--font-body); border: none; }

.btn-primary {
  background: var(--red); color: var(--white);
  padding: 13px 30px;
  font-family: var(--font-display); font-size: 19px; letter-spacing: 0.06em;
  border-radius: var(--radius);
  transition: background 0.25s var(--ease), transform 0.15s;
  animation: pulse-glow 3s ease-in-out infinite;
}
.btn-primary:hover { background: var(--red-light); transform: translateY(-2px); }

.btn-secondary {
  background: transparent; color: var(--white);
  border: 2px solid rgba(255,255,255,0.4);
  padding: 12px 26px;
  font-family: var(--font-display); font-size: 19px; letter-spacing: 0.06em;
  border-radius: var(--radius);
  transition: border-color 0.25s var(--ease), transform 0.15s;
}
.btn-secondary:hover { border-color: var(--white); transform: translateY(-2px); }

.btn-outline {
  background: transparent; color: var(--white);
  border: 2px solid rgba(255,255,255,0.45);
  padding: 12px 26px;
  font-family: var(--font-display); font-size: 18px; letter-spacing: 0.06em;
  border-radius: var(--radius);
  transition: border-color 0.25s var(--ease);
}
.btn-outline:hover { border-color: var(--white); }

@keyframes pulse-glow {
  0%,100% { box-shadow: 0 0 0 0 rgba(200,16,46,0); }
  50%      { box-shadow: 0 0 20px 4px rgba(200,16,46,0.35); }
}

/* ── SHARED TYPOGRAPHY ────────────────────────────────────────────────── */
.eyebrow {
  display: flex; align-items: center; gap: 10px;
  font-size: 12px; font-weight: 700; letter-spacing: 0.2em; text-transform: uppercase;
  color: rgba(255,255,255,0.5); margin-bottom: 14px;
}
.eyebrow::before { content: ''; width: 22px; height: 2px; background: currentColor; display: block; flex-shrink: 0; }
.eyebrow-gold { color: var(--gold); }
.eyebrow-gold::before { background: var(--gold); }

.section-sub-label {
  display: block;
  font-size: 12px; font-weight: 700; letter-spacing: 0.2em; text-transform: uppercase;
  color: var(--red); margin-bottom: 10px;
}
.section-title {
  font-family: var(--font-display);
  font-size: clamp(32px, 4.5vw, 58px);
  line-height: 1; text-transform: uppercase; color: var(--white);
}
.section-desc {
  font-size: 15px; color: var(--muted); margin-top: 12px;
  max-width: 400px; margin-left: auto; margin-right: auto; line-height: 1.6;
}
.t-red  { color: var(--red); }
.t-gold { color: var(--gold); }

.section-header        { margin-bottom: 3rem; }
.section-header.centered { text-align: center; }
.section-cta           { text-align: center; margin-top: 2.5rem; }
.container             { max-width: 1200px; margin: 0 auto; padding: 0 2rem; }

/* ── HERO ─────────────────────────────────────────────────────────────── */
.hero {
  position: relative;
  height: 100vh; min-height: 560px;
  overflow: hidden;
  display: grid;
  grid-template-columns: 1fr 1fr;
}

/* bg layers */
.hero-bg {
  position: absolute; inset: 0;
  opacity: 0; transition: opacity 0.75s var(--ease);
  z-index: 0;
}
.hero-bg.bg-active { opacity: 1; }
.hero-bg.bg-exit   { opacity: 0; }

.hero-noise {
  position: absolute; inset: 0; opacity: 0.04;
  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)'/%3E%3C/svg%3E");
  background-size: 150px;
}
.hero-dots {
  position: absolute; inset: 0;
  background-image: radial-gradient(rgba(255,255,255,0.07) 1px, transparent 1px);
  background-size: 40px 40px;
}

/* slides */
.hero-slide {
  position: absolute; inset: 0;
  display: flex; align-items: center;
  padding: 0 7vw;
  z-index: 2;
  opacity: 0; transform: translateX(50px);
  transition: opacity 0.55s var(--ease), transform 0.55s var(--ease);
  pointer-events: none;
}
.hero-slide.slide-active { opacity: 1; transform: translateX(0); pointer-events: auto; }
.hero-slide.slide-exit   { opacity: 0; transform: translateX(-50px); }

.hero-content {
  max-width: 560px;
  opacity: 0; transform: translateY(28px);
  transition: opacity 0.9s var(--ease) 0.15s, transform 0.9s var(--ease) 0.15s;
}
.hero-content.visible { opacity: 1; transform: none; }

.hero-badge {
  display: inline-flex; align-items: center; gap: 8px;
  background: rgba(200,16,46,0.18); border: 1px solid rgba(200,16,46,0.35);
  color: var(--gold);
  font-size: 11px; font-weight: 700; letter-spacing: 0.14em; text-transform: uppercase;
  padding: 5px 14px; border-radius: 99px;
  margin-bottom: 20px;
}
.badge-dot {
  width: 6px; height: 6px; border-radius: 50%; background: var(--gold);
  animation: bpulse 2s infinite;
}
@keyframes bpulse { 0%,100% { opacity:1; transform:scale(1); } 50% { opacity:0.4; transform:scale(0.7); } }

.hero-headline { font-family: var(--font-display); line-height: 0.88; margin-bottom: 22px; }
.hl-solid   { display: block; font-size: clamp(60px, 9vw, 110px); color: var(--white); }
.hl-outline {
  display: block; font-size: clamp(64px, 10vw, 118px);
  -webkit-text-stroke: 2px var(--white); color: transparent;
}

.hero-sub  { font-size: clamp(15px, 2vw, 18px); line-height: 1.65; color: rgba(255,255,255,0.75); margin-bottom: 14px; }
.hero-pill {
  display: inline-block;
  background: var(--white); color: var(--red);
  font-size: 13px; font-weight: 700; letter-spacing: 0.06em;
  padding: 6px 16px; border-radius: 99px; margin-bottom: 30px;
}
.hero-ctas { display: flex; gap: 12px; flex-wrap: wrap; }

/* visual panel */
.hero-visual {
  position: absolute; right: 0; top: 0; bottom: 0;
  width: 48%; z-index: 1;
  display: flex; align-items: center; justify-content: center;
  opacity: 0; transform: translateX(40px) scale(0.97);
  transition: opacity 0.9s var(--ease) 0.3s, transform 0.9s var(--ease) 0.3s;
}
.hero-visual.visible { opacity: 1; transform: none; }

.hero-img-wrap { position: relative; width: 82%; }
.hero-main-img { border-radius: 20px !important; overflow: hidden !important; box-shadow: var(--shadow-dark) !important; animation: float 6s ease-in-out infinite; }

@keyframes float { 0%,100% { transform: translateY(0); } 50% { transform: translateY(-10px); } }

.hero-float-card {
  position: absolute;
  background: rgba(22,22,22,0.95); backdrop-filter: blur(20px);
  border: 1px solid rgba(255,255,255,0.1);
  border-radius: var(--radius-lg);
  padding: 12px 18px;
  display: flex; align-items: center; gap: 10px;
  box-shadow: var(--shadow-dark);
  animation: float 6s ease-in-out infinite;
}
.hero-float-card span { font-size: 1.5rem; }
.hero-float-card strong { display: block; font-size: 0.85rem; color: var(--white); }
.hero-float-card p  { font-size: 0.72rem; color: var(--muted); margin: 0; }
.card-1 { bottom: -22px; left: -28px; animation-delay: -2s; }
.card-2 { top: -20px; right: -20px; animation-delay: -4s; }

/* controls */
.hero-controls {
  position: absolute; bottom: 2rem; left: 7vw; z-index: 10;
  display: flex; align-items: center; gap: 18px;
}
.slide-dots { display: flex; gap: 7px; }
.sdot {
  width: 8px; height: 8px; border-radius: 99px; border: none;
  background: rgba(255,255,255,0.35);
  transition: all 0.3s;
}
.sdot.sdot-active { background: var(--white); width: 26px; }
.slide-arrows { display: flex; gap: 7px; }
.sarrow {
  width: 40px; height: 40px; border-radius: 50%;
  background: rgba(255,255,255,0.12); border: 1px solid rgba(255,255,255,0.25);
  color: var(--white); font-size: 16px;
  display: flex; align-items: center; justify-content: center;
  transition: background 0.2s;
}
.sarrow:hover { background: rgba(255,255,255,0.25); }

.hero-scroll-hint {
  position: absolute; bottom: 2rem; left: 50%; transform: translateX(-50%);
  display: flex; flex-direction: column; align-items: center; gap: 6px;
  color: rgba(255,255,255,0.3); font-size: 10px; letter-spacing: 0.15em; text-transform: uppercase;
  z-index: 3;
}
.scroll-line { width: 1px; height: 36px; background: linear-gradient(to bottom, rgba(255,255,255,0.5), transparent); animation: float 2s ease-in-out infinite; }

/* ── STATS BAR ────────────────────────────────────────────────────────── */
.stats-bar {
  background: var(--red);
  padding: 1.75rem 2rem;
  display: flex; justify-content: center;
}
.stat-item {
  display: flex; flex-direction: column; align-items: center;
  padding: 0 3rem;
  border-right: 1px solid rgba(255,255,255,0.2);
}
.stat-item:last-child { border-right: none; }
.stat-value { font-family: var(--font-display); font-size: 2.4rem; color: var(--white); letter-spacing: 0.05em; }
.stat-label { font-size: 0.72rem; font-weight: 600; color: rgba(255,255,255,0.72); letter-spacing: 0.12em; text-transform: uppercase; margin-top: 2px; }

/* ── TAPE ─────────────────────────────────────────────────────────────── */
.tape {
  background: var(--charcoal);
  border-top: 1px solid rgba(200,16,46,0.2);
  border-bottom: 1px solid rgba(200,16,46,0.2);
  padding: 12px 2rem;
  display: flex; align-items: center; gap: 20px; overflow: hidden;
}
.tape-track {
  flex: 1; display: flex; white-space: nowrap; overflow: hidden;
  font-family: var(--font-display); font-size: 17px; color: rgba(255,255,255,0.4);
  letter-spacing: 0.08em;
}
.tape-track span { animation: marquee 20s linear infinite; display: inline-block; }
@keyframes marquee { 0% { transform: translateX(0); } 100% { transform: translateX(-33.33%); } }
.tape-btn {
  background: var(--red); color: var(--white);
  padding: 9px 22px; border-radius: var(--radius);
  font-family: var(--font-display); font-size: 16px; letter-spacing: 0.06em;
  flex-shrink: 0; transition: background 0.2s;
}
.tape-btn:hover { background: var(--red-light); }

/* ── STORY ────────────────────────────────────────────────────────────── */
.story-section {
  background: var(--red);
  padding: 80px 7vw;
  display: grid; grid-template-columns: 1fr 1fr;
  gap: 60px; align-items: center;
}
.story-title {
  font-family: var(--font-display);
  font-size: clamp(32px, 4.5vw, 54px);
  color: var(--white); line-height: 1; text-transform: uppercase; margin-bottom: 20px;
}
.story-body { font-size: 15px; line-height: 1.75; color: rgba(255,255,255,0.78); margin-bottom: 30px; max-width: 440px; }
.story-img-col { position: relative; }
.story-img-frame { border: 3px dashed rgba(255,255,255,0.3); border-radius: 4px; overflow: hidden; }
.story-float-tag {
  position: absolute; bottom: -16px; right: -16px;
  background: var(--white); color: var(--red);
  font-family: var(--font-display); font-size: 13px; letter-spacing: 0.08em;
  padding: 12px 18px; border-radius: var(--radius); box-shadow: var(--shadow);
}

/* ── MENU ─────────────────────────────────────────────────────────────── */
.menu-section { padding: 90px 0; background: var(--charcoal); }
.menu-grid { display: grid; grid-template-columns: repeat(4,1fr); gap: 18px; }
.menu-card {
  background: rgba(255,255,255,0.04); border: 1px solid var(--border);
  border-radius: var(--radius-lg); overflow: hidden; cursor: pointer;
  transition: transform 0.35s var(--ease), border-color 0.35s, box-shadow 0.35s;
}
.menu-card:hover { transform: translateY(-6px); border-color: rgba(200,16,46,0.35); box-shadow: var(--shadow); }
.menu-card-img { position: relative; overflow: hidden; }
.menu-card-img .placeholder-img { border-radius: 0; }
.menu-card-overlay {
  position: absolute; inset: 0;
  background: linear-gradient(to top, rgba(0,0,0,0.65) 0%, transparent 55%);
  display: flex; flex-direction: column; justify-content: flex-end; padding: 16px;
}
.mc-name  { font-family: var(--font-display); font-size: 20px; color: var(--white); letter-spacing: 0.04em; text-transform: uppercase; line-height: 1; }
.mc-count { font-size: 11px; color: rgba(255,255,255,0.6); font-weight: 600; letter-spacing: 0.1em; margin-top: 4px; }
.menu-card-foot { padding: 12px 16px; display: flex; align-items: center; justify-content: space-between; }
.mc-emoji { font-size: 20px; }
.mc-arrow {
  width: 30px; height: 30px; border-radius: 50%;
  background: var(--red); color: var(--white);
  display: flex; align-items: center; justify-content: center; font-size: 13px;
  transition: transform 0.2s;
}
.menu-card:hover .mc-arrow { transform: rotate(-45deg); }

/* ── FEATURED ─────────────────────────────────────────────────────────── */
.featured-section { padding: 90px 0; background: var(--black); }
.featured-grid { display: grid; grid-template-columns: repeat(4,1fr); gap: 1.4rem; margin-bottom: 2rem; }
.feat-card {
  background: var(--charcoal); border-radius: var(--radius-lg); overflow: hidden;
  border: 1px solid var(--border);
  transition: transform 0.35s var(--ease), border-color 0.35s, box-shadow 0.35s;
  animation: fadeInUp 0.6s ease both;
}
@keyframes fadeInUp { from { opacity:0; transform:translateY(24px); } to { opacity:1; transform:none; } }
.feat-card:hover { transform: translateY(-8px); border-color: rgba(200,16,46,0.3); box-shadow: var(--shadow); }
.feat-card-img  { position: relative; overflow: hidden; }
.feat-card-img .placeholder-img { border-radius: 0; }
.feat-tag {
  position: absolute; top: 10px; left: 10px;
  background: var(--red); color: var(--white);
  font-size: 10px; font-weight: 700; letter-spacing: 0.1em; text-transform: uppercase;
  padding: 4px 8px; border-radius: var(--radius);
}
.feat-heat { position: absolute; bottom: 10px; right: 10px; font-size: 13px; }
.feat-card-body { padding: 1.2rem; }
.feat-card-body h3 { font-family: var(--font-serif); font-size: 1rem; font-weight: 700; color: var(--white); margin-bottom: 6px; }
.feat-card-body p  { font-size: 0.78rem; color: var(--muted); line-height: 1.55; margin-bottom: 1rem; }
.feat-footer { display: flex; align-items: center; justify-content: space-between; }
.feat-price  { font-family: var(--font-display); font-size: 1.35rem; color: var(--gold); letter-spacing: 0.05em; }
.feat-btn {
  background: var(--red); color: var(--white);
  font-size: 0.72rem; font-weight: 700; letter-spacing: 0.1em; text-transform: uppercase;
  padding: 7px 14px; border-radius: var(--radius);
  transition: background 0.2s, transform 0.15s;
}
.feat-btn:hover { background: var(--red-light); transform: scale(1.04); }

/* ── WHY ──────────────────────────────────────────────────────────────── */
.why-section { padding: 90px 0; background: var(--charcoal); }
.why-inner   { display: grid; grid-template-columns: 1fr 1fr; gap: 5rem; align-items: center; }
.why-title {
  font-family: var(--font-display);
  font-size: clamp(36px, 4.5vw, 58px); line-height: 1;
  color: var(--white); text-transform: uppercase; margin-bottom: 20px;
}
.why-desc  { color: rgba(255,255,255,0.6); line-height: 1.8; margin-bottom: 2rem; font-size: 15px; }
.why-right { display: grid; grid-template-columns: 1fr 1fr; gap: 1.2rem; }
.feature-card {
  background: rgba(255,255,255,0.04); border: 1px solid var(--border);
  border-radius: var(--radius-lg); padding: 1.4rem;
  transition: background 0.3s, border-color 0.3s, transform 0.3s;
}
.feature-card:hover { background: rgba(200,16,46,0.08); border-color: rgba(200,16,46,0.22); transform: translateY(-4px); }
.feature-icon { font-size: 1.6rem; margin-bottom: 0.65rem; }
.feature-card h4 { font-family: var(--font-serif); font-size: 0.9rem; font-weight: 700; color: var(--white); margin-bottom: 6px; }
.feature-card p  { font-size: 0.77rem; color: var(--muted); line-height: 1.6; }

/* ── GALLERY ──────────────────────────────────────────────────────────── */
.gallery-section { padding: 90px 0; background: var(--black); }
.gallery-grid {
  display: grid;
  grid-template-columns: repeat(3,1fr);
  grid-template-rows: 250px 250px;
  gap: 10px;
}
.gallery-item { border-radius: var(--radius-lg); overflow: hidden; position: relative; cursor: pointer; }
.gallery-item .placeholder-img { height: 100% !important; border-radius: 0 !important; }
.g-1 { grid-row: 1 / 3; }
.g-4 { grid-row: 1 / 3; }
.gallery-overlay {
  position: absolute; inset: 0;
  background: rgba(200,16,46,0); color: var(--white);
  font-weight: 600; font-size: 1rem;
  display: flex; align-items: center; justify-content: center;
  opacity: 0; transition: all 0.3s;
}
.gallery-item:hover .gallery-overlay { background: rgba(200,16,46,0.55); opacity: 1; }

/* ── TESTIMONIALS ─────────────────────────────────────────────────────── */
.testimonials-section { padding: 90px 0; background: var(--charcoal); }
.testimonials-grid { display: grid; grid-template-columns: repeat(3,1fr); gap: 1.4rem; }
.testimonial-card {
  background: rgba(255,255,255,0.04); border: 1px solid var(--border);
  border-radius: var(--radius-lg); padding: 1.8rem;
  transition: border-color 0.3s, transform 0.3s;
}
.testimonial-card:hover { border-color: rgba(200,16,46,0.3); transform: translateY(-4px); }
.t-stars { font-size: 1rem; margin-bottom: 1rem; }
.t-text  { font-family: var(--font-serif); font-style: italic; font-size: 0.92rem; line-height: 1.7; color: rgba(255,255,255,0.75); margin-bottom: 1.4rem; }
.t-author { display: flex; align-items: center; gap: 12px; }
.t-avatar {
  width: 42px; height: 42px; border-radius: 50%;
  background: var(--red); flex-shrink: 0;
  display: flex; align-items: center; justify-content: center;
  font-family: var(--font-display); font-size: 1.15rem; color: var(--white);
}
.t-author strong { display: block; font-size: 0.85rem; color: var(--white); }
.t-author span   { font-size: 0.73rem; color: rgba(255,255,255,0.4); }

/* ── CTA BANNER ───────────────────────────────────────────────────────── */
.cta-banner     { position: relative; padding: 6rem 2rem; text-align: center; overflow: hidden; background: var(--black); }
.cta-banner-bg  { position: absolute; inset: 0; background: radial-gradient(ellipse 100% 100% at 50% 50%, rgba(200,16,46,0.28) 0%, var(--black) 70%); }
.cta-content    { position: relative; z-index: 1; }
.cta-content h2 { font-family: var(--font-display); font-size: clamp(2rem, 5vw, 4rem); letter-spacing: 0.05em; color: var(--white); margin-bottom: 1rem; }
.cta-content p  { color: var(--muted); font-size: 1rem; margin-bottom: 2.4rem; }
.cta-buttons    { display: flex; justify-content: center; gap: 1rem; flex-wrap: wrap; }

/* ── NEWSLETTER ───────────────────────────────────────────────────────── */
.newsletter-section {
  background: var(--red); padding: 70px 7vw;
  display: grid; grid-template-columns: 1fr 1fr; gap: 60px; align-items: center;
}
.nl-headline { font-family: var(--font-display); font-size: clamp(26px, 3.5vw, 44px); color: var(--white); text-transform: uppercase; line-height: 1.05; }
.nl-sub      { font-size: 14px; color: rgba(255,255,255,0.72); margin-top: 10px; }
.nl-form     { display: flex; max-width: 480px; }
.nl-input {
  flex: 1; padding: 14px 18px;
  background: rgba(255,255,255,0.12); border: 1px solid rgba(255,255,255,0.25); border-right: none;
  border-radius: var(--radius) 0 0 var(--radius);
  font-family: var(--font-body); font-size: 14px; color: var(--white); outline: none;
}
.nl-input::placeholder { color: rgba(255,255,255,0.45); }
.nl-btn {
  padding: 14px 22px; background: var(--white); color: var(--red);
  font-family: var(--font-display); font-size: 16px; letter-spacing: 0.06em;
  border-radius: 0 var(--radius) var(--radius) 0; transition: opacity 0.2s;
}
.nl-btn:hover { opacity: 0.88; }

/* ── FOOTER ───────────────────────────────────────────────────────────── */
.footer-bar {
  background: #0a0a0a; padding: 36px 7vw;
  display: flex; align-items: center; justify-content: space-between; gap: 24px; flex-wrap: wrap;
}
.footer-nav { display: flex; gap: 28px; flex-wrap: wrap; }
.footer-nav a {
  font-size: 12px; font-weight: 700; letter-spacing: 0.14em; text-transform: uppercase;
  color: rgba(255,255,255,0.4); text-decoration: none; cursor: pointer; transition: color 0.2s;
}
.footer-nav a:hover { color: var(--white); }
.footer-copy { font-size: 11px; color: rgba(255,255,255,0.25); }

/* ── RESPONSIVE ───────────────────────────────────────────────────────── */
@media (max-width: 1024px) {
  .featured-grid { grid-template-columns: repeat(2,1fr); }
  .menu-grid     { grid-template-columns: repeat(2,1fr); }
}
@media (max-width: 900px) {
  .story-section, .newsletter-section { grid-template-columns: 1fr; }
  .why-inner { grid-template-columns: 1fr; gap: 3rem; }
  .why-right { grid-template-columns: 1fr 1fr; }
}
@media (max-width: 768px) {
  .hero { grid-template-columns: 1fr; }
  .hero-visual { display: none; }
  .hero-slide  { padding: 0 1.5rem; }
  .stats-bar   { flex-wrap: wrap; }
  .stat-item   { padding: 0.5rem 1.2rem; border-right: none; border-bottom: 1px solid rgba(255,255,255,0.1); width: 50%; }
  .stat-item:nth-child(odd) { border-right: 1px solid rgba(255,255,255,0.1); }
  .featured-grid, .menu-grid, .testimonials-grid { grid-template-columns: 1fr; }
  .gallery-grid { grid-template-columns: 1fr 1fr; grid-template-rows: auto; }
  .g-1, .g-4   { grid-row: auto; }
  .why-right   { grid-template-columns: 1fr; }
  .footer-bar  { flex-direction: column; align-items: flex-start; }
}
