        </section>

        {/* ══ GALLERY ══════════════════════════════════════════════════ */}
        <section className="gallery-section">
          <div className="container">
            <div className="section-header centered">
              <p className="section-sub-label">Food Gallery</p>
              <h2 className="section-title">Eat With Your <span className="t-gold">Eyes First</span></h2>
